mapper.select:
SELECT a.id, a.country AS 'country', a.channel AS 'channel', a.hot_type AS 'hotType', d1.`label` AS 'hotTypes', a.hot_level AS 'hotLevel', l.`name` AS 'hotLevels', a.video_type AS 'videoType', d2.`label` AS 'videoTypes', a.view_target AS 'viewTarget', a.iactr_target AS 'iactrTarget', a.clickr_target AS 'clickrTarget', a.conver_target AS 'converTarget', a.cpm_target AS 'cpmTarget', a.roas_target AS 'roasTarget' FROM `a_hot_target` a LEFT JOIN `a_hot_level` l ON l.`id` = a.hot_level LEFT JOIN `sys_dict` d1 ON d1.`value` = a.hot_type AND d1.`type` = 'hot_type' AND d1.`del_flag` = 0 LEFT JOIN `sys_dict` d2 ON d2.`value` = a.video_type AND d2.`type` = 'vid_type' AND d2.`del_flag` = 0 WHERE a.del_flag = '0'
AND a.country LIKE CONCAT('%', #{country}, '%')
AND a.channel = #{channel}
AND a.hot_type = #{hotType}
AND a.hot_level = #{hotLevel}
AND a.video_type = #{videoType}
ORDER BY a.create_time DESC
